(function(){"use strict";var widget=document.getElementById("wpau_pending_users");if(!widget)return;var i18n=window.wp_approve_user_dashboard||{};widget.addEventListener("click",function(event){var button=event.target.closest("[data-wpau-action]");if(!button||!widget.contains(button))return;event.preventDefault();var row=button.closest(".wpau-pending-row");if(!row)return;runAction(row,button.dataset.wpauAction)});function runAction(row,action){var userId=row.dataset.userId;var nonce=action==="approve"?row.dataset.nonceApprove:row.dataset.nonceUnapprove;toggleButtons(row,true);clearError(row);postForm(i18n.ajaxurl,{action:"wpau_dashboard_"+action,user_id:userId,nonce:nonce}).then(function(response){if(!response||!response.success){showError(row,response&&response.data&&response.data.code==="cap"?i18n.errorPermission:i18n.errorGeneric,action);return}removeRow(row,response.data)}).catch(function(error){console.error("WPAU dashboard widget",error);showError(row,i18n.errorGeneric,action)})}function removeRow(row,data){var list=row.parentNode;row.classList.add("is-removing");window.setTimeout(function(){list.removeChild(row);appendNextRow(list,data.next_row);updateFooter(data);maybeOfferRefresh(data.pending_count)},200)}function appendNextRow(list,html){if(!html)return;if(!list||list.tagName!=="UL")return;var template=document.createElement("template");template.innerHTML=html.trim();var newRow=template.content.firstElementChild;if(!newRow){console.error("WPAU dashboard widget","invalid next_row markup");return}if(list.querySelector('[data-user-id="'+newRow.dataset.userId+'"]'))return;list.appendChild(newRow)}function updateFooter(data){var footer=widget.querySelector(".wpau-widget-footer");if(!footer)return;if(data.pending_count<=0){footer.parentNode.removeChild(footer);return}var link=footer.querySelector("a");if(link)link.textContent=data.pending_label}function maybeOfferRefresh(pendingCount){var list=widget.querySelector("[data-wpau-container]");if(!list||list.children.length>0)return;if(pendingCount<=0){var empty=document.createElement("p");empty.className="wpau-widget-empty";empty.textContent=i18n.emptyMessage;list.parentNode.replaceChild(empty,list);return}var wrap=document.createElement("p");wrap.className="wpau-widget-refresh";var btn=document.createElement("button");btn.type="button";btn.className="button button-secondary";btn.textContent=i18n.refreshLabel;btn.addEventListener("click",refresh);wrap.appendChild(btn);list.parentNode.replaceChild(wrap,list)}function refresh(event){var btn=event.currentTarget;btn.disabled=true;clearRefreshError(btn);postForm(i18n.ajaxurl,{action:"wpau_dashboard_refresh",nonce:i18n.refreshNonce}).then(function(response){if(!response||!response.success){btn.disabled=false;showRefreshError(btn);return}if(response.data.pending_count>0&&!response.data.html){console.error("WPAU dashboard widget","empty html with pending_count > 0");btn.disabled=false;showRefreshError(btn);return}var replacement;if(response.data.pending_count<=0){replacement=document.createElement("p");replacement.className="wpau-widget-empty";replacement.textContent=i18n.emptyMessage}else{replacement=document.createElement("ul");replacement.className="wpau-pending-list";replacement.setAttribute("data-wpau-container","");replacement.innerHTML=response.data.html}var wrap=btn.closest(".wpau-widget-refresh");wrap.parentNode.replaceChild(replacement,wrap);updateFooter(response.data)}).catch(function(error){console.error("WPAU dashboard widget",error);btn.disabled=false;showRefreshError(btn)})}function showRefreshError(btn){var wrap=btn.closest(".wpau-widget-refresh");if(!wrap||wrap.querySelector(".wpau-widget-error"))return;var notice=document.createElement("div");notice.className="notice notice-error inline wpau-widget-error";notice.setAttribute("role","alert");notice.textContent=i18n.errorGeneric;wrap.appendChild(notice)}function clearRefreshError(btn){var wrap=btn.closest(".wpau-widget-refresh");var existing=wrap&&wrap.querySelector(".wpau-widget-error");if(existing)existing.parentNode.removeChild(existing)}function showError(row,message,action){toggleButtons(row,false);var notice=document.createElement("div");notice.className="notice notice-error inline wpau-widget-error";notice.setAttribute("role","alert");notice.textContent=message+" ";var retry=document.createElement("a");retry.href="#";retry.textContent=i18n.retryLabel;retry.addEventListener("click",function(event){event.preventDefault();notice.parentNode.removeChild(notice);runAction(row,action)});notice.appendChild(retry);row.appendChild(notice)}function clearError(row){var existing=row.querySelector(".wpau-widget-error");if(existing)existing.parentNode.removeChild(existing)}function toggleButtons(row,disabled){row.querySelectorAll("button").forEach(function(btn){btn.disabled=disabled})}function postForm(url,params){var body=new URLSearchParams();Object.keys(params).forEach(function(key){if(params[key]!==undefined&&params[key]!==null)body.append(key,params[key])});return window.fetch(url,{method:"POST",credentials:"same-origin",body:body}).then(function(response){return response.json().catch(function(){var err=new Error("Non-JSON response");err.status=response.status;throw err})})}})();
